import React, { useState } from 'react';
import toast from 'react-hot-toast';

const FEE_STRUCTURE = [
  {type:'Tuition Fee',freq:'Monthly',c6:'₹1,200',c9:'₹1,500',c11:'₹1,800',due:'10th',fine:'₹10/day'},
  {type:'Admission Fee',freq:'One-time',c6:'₹2,000',c9:'₹2,500',c11:'₹3,000',due:'At admission',fine:'—'},
  {type:'Exam Fee',freq:'Per Term',c6:'₹500',c9:'₹600',c11:'₹700',due:'15 days prior',fine:'₹5/day'},
  {type:'Transport Fee',freq:'Monthly',c6:'₹800',c9:'₹800',c11:'₹800',due:'5th',fine:'₹5/day'},
  {type:'Annual Fee',freq:'Yearly',c6:'₹1,500',c9:'₹2,000',c11:'₹2,500',due:'30 April',fine:'₹15/day'},
  {type:'Library Fee',freq:'Yearly',c6:'₹300',c9:'₹400',c11:'₹400',due:'30 April',fine:'—'},
];

const PENDING = [
  {name:'Priya Singh',cls:'Class 8B',phone:'9765432100',amt:'₹1,200',months:'Jun'},
  {name:'Dev Kumar',cls:'Class 11B',phone:'9543218760',amt:'₹3,000',months:'May, Jun'},
  {name:'Vikram Joshi',cls:'Class 8A',phone:'9876001234',amt:'₹1,200',months:'Jun'},
  {name:'Ananya Patel',cls:'Class 6C',phone:'9765432108',amt:'₹600',months:'Jun (partial)'},
  {name:'Neha Tiwari',cls:'Class 10B',phone:'9634567890',amt:'₹750',months:'Jun (partial)'},
];

export default function FeeManagement() {
  const [tab,setTab]=useState(0);
  const [showModal,setShowModal]=useState(false);
  const [form,setForm]=useState({student:'',type:'Tuition Fee',amount:'',mode:'cash'});

  const tabs=['Fee Structure','Recent Collections','Pending Dues'];

  const handleCollect=(e)=>{
    e.preventDefault();
    toast.success(`Fee collected! Receipt No: REC${Date.now().toString().slice(-6)}`);
    setShowModal(false);
    setForm({student:'',type:'Tuition Fee',amount:'',mode:'cash'});
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Fee Management</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Collect and track school fees</p></div>
        <button onClick={()=>setShowModal(true)} style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>+ Collect Fee</button>
      </div>

      {/* Summary */}
      <div style={{display:'flex',gap:10,flexWrap:'wrap',marginBottom:16}}>
        {[['💵 Collected (YTD)','₹28,40,000','#D1FAE5','#065F46'],['⚠️ Pending','₹4,80,000','#FEE2E2','#991B1B'],['📅 Today','₹1,20,000','#EDE9F8','#2D1B69'],['🎓 Students with dues','312','#FEF3C7','#92400E']].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'9px 14px',borderRadius:10,background:bg,color:c,fontSize:12,fontWeight:600,display:'flex',gap:8,alignItems:'center'}}>
            {l}: <strong>{v}</strong>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{display:'flex',borderBottom:'1px solid #E5E7EB',marginBottom:16}}>
        {tabs.map((t,i)=>(
          <div key={t} onClick={()=>setTab(i)} style={{padding:'9px 16px',fontSize:12,fontWeight:600,cursor:'pointer',borderBottom:`2px solid ${tab===i?'#2D1B69':'transparent'}`,color:tab===i?'#2D1B69':'#6B7280',marginBottom:-1,transition:'all .12s'}}>{t}</div>
        ))}
      </div>

      {tab===0 && (
        <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
          <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
            <thead><tr style={{background:'#F9FAFB'}}>
              {['Fee Type','Frequency','Class 6–8','Class 9–10','Class 11–12','Due Date','Late Fine'].map(h=>(
                <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB'}}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {FEE_STRUCTURE.map((f,i)=>(
                <tr key={i} style={{borderBottom:'0.5px solid #F3F4F6'}}>
                  <td style={{padding:'11px 12px',fontWeight:600}}>{f.type}</td>
                  <td style={{padding:'11px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#EDE9F8',color:'#2D1B69'}}>{f.freq}</span></td>
                  <td style={{padding:'11px 12px'}}>{f.c6}</td>
                  <td style={{padding:'11px 12px'}}>{f.c9}</td>
                  <td style={{padding:'11px 12px'}}>{f.c11}</td>
                  <td style={{padding:'11px 12px',color:'#6B7280'}}>{f.due}</td>
                  <td style={{padding:'11px 12px',color:'#6B7280'}}>{f.fine}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {tab===2 && (
        <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
          <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
            <thead><tr style={{background:'#F9FAFB'}}>
              {['Student','Class','Mobile','Pending Months','Amount','Action'].map(h=>(
                <th key={h} style={{padding:'9px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:600,textTransform:'uppercase',borderBottom:'0.5px solid #E5E7EB'}}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {PENDING.map((p,i)=>(
                <tr key={i} style={{borderBottom:'0.5px solid #F3F4F6'}}>
                  <td style={{padding:'11px 12px',fontWeight:600}}>{p.name}</td>
                  <td style={{padding:'11px 12px',color:'#6B7280'}}>{p.cls}</td>
                  <td style={{padding:'11px 12px',color:'#6B7280'}}>{p.phone}</td>
                  <td style={{padding:'11px 12px'}}><span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#FEF3C7',color:'#92400E'}}>{p.months}</span></td>
                  <td style={{padding:'11px 12px',fontWeight:700,color:'#DC2626'}}>{p.amt}</td>
                  <td style={{padding:'11px 12px'}}>
                    <button onClick={()=>{setForm({...form,student:p.name});setShowModal(true);}} style={{padding:'4px 10px',border:'1px solid #2D1B69',borderRadius:6,background:'#EDE9F8',color:'#2D1B69',fontSize:11,fontWeight:600,cursor:'pointer'}}>Collect</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {tab===1 && (
        <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:40,textAlign:'center',color:'#9CA3AF'}}>
          <div style={{fontSize:32,marginBottom:10}}>💳</div>
          <div style={{fontSize:14,fontWeight:600,color:'#6B7280'}}>Recent Collections</div>
          <div style={{fontSize:12,marginTop:4}}>Connect to backend API to see live collection data</div>
        </div>
      )}

      {/* Collect Fee Modal */}
      {showModal && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.4)',zIndex:200,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:16,width:480,maxWidth:'100%',overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>💰 Collect Fee Payment</div>
              <button onClick={()=>setShowModal(false)} style={{background:'#F3F4F6',border:'none',borderRadius:6,width:28,height:28,cursor:'pointer',fontSize:14}}>✕</button>
            </div>
            <form onSubmit={handleCollect} style={{padding:20}}>
              {[['Student *','student','text','Search by name or admission no…'],['Amount (₹) *','amount','number','0.00']].map(([label,field,type,ph])=>(
                <div key={field} style={{marginBottom:12}}>
                  <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em',display:'block',marginBottom:5}}>{label}</label>
                  <input type={type} value={form[field]} onChange={e=>setForm({...form,[field]:e.target.value})} placeholder={ph} required
                    style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none'}}/>
                </div>
              ))}
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div>
                  <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em',display:'block',marginBottom:5}}>Fee Type</label>
                  <select value={form.type} onChange={e=>setForm({...form,type:e.target.value})} style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none'}}>
                    {['Tuition Fee','Admission Fee','Transport Fee','Exam Fee','Annual Fee','Library Fee'].map(t=><option key={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em',display:'block',marginBottom:5}}>Payment Mode</label>
                  <select value={form.mode} onChange={e=>setForm({...form,mode:e.target.value})} style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none'}}>
                    {['cash','upi','bank_transfer','cheque'].map(m=><option key={m} value={m}>{m.replace('_',' ').toUpperCase()}</option>)}
                  </select>
                </div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end',paddingTop:12,borderTop:'0.5px solid #E5E7EB'}}>
                <button type="button" onClick={()=>setShowModal(false)} style={{padding:'8px 16px',border:'1px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>💾 Collect & Generate Receipt</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
